    pid_t pid;
    JobState state;
    char name[32];
} Job;

int add_job(pid_t pid, const char *name);
void print_jobs(void);
void job_bg(int idx);

Job jobs[MAX_JOBS];
int njobs = 0;

void test_add_job(void) {
    njobs = 0;
    int idx = add_job(getpid(), "test_job");
    TEST_ASSERT_EQUAL_INT(0, idx);
    TEST_ASSERT_EQUAL_INT(1, njobs);
    TEST_ASSERT_EQUAL_STRING("test_job", jobs[0].name);
}

void test_job_state_running(void) {
    njobs = 0;
    add_job(getpid(), "worker");
    TEST_ASSERT_EQUAL_INT(JOB_RUNNING, jobs[0].state);
}

void test_job_state_transition(void) {
    njobs = 0;
    add_job(getpid(), "worker");
    jobs[0].state = JOB_STOPPED;
    TEST_ASSERT_EQUAL_INT(JOB_STOPPED, jobs[0].state);
    jobs[0].state = JOB_DONE;
    TEST_ASSERT_EQUAL_INT(JOB_DONE, jobs[0].state);
}

int main(void) {
    RUN_TEST(test_add_job);
    RUN_TEST(test_job_state_running);
    RUN_TEST(test_job_state_transition);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

