void example_stop_continue(void) {
    pid_t child = fork();
    if (child == 0) {
        while (1) pause();
        exit(0);
    }
    usleep(50000);
    printf("Stopping child %d\n", child);
    kill(child, SIGSTOP);
    int st;
    waitpid(child, &st, WUNTRACED);
    if (WIFSTOPPED(st)) printf("Child stopped\n");
    printf("Continuing child\n");
    kill(child, SIGCONT);
    usleep(50000);
    kill(child, SIGTERM);
    waitpid(child, &st, 0);
    printf("Child done\n");
}
